  const [error, setError] = useState(null);

  useEffect(() => {
    if (!notificationElem) {
      setError('Notification element not found');
    }
  }, [notificationElem]);

  const triggerNotification = async (props: any) => {
    if (!notificationElem) return;
    try {
      await notify(notificationElem, props);
    } catch (error) {
      setError(error.message);
    }
  };

  return { triggerNotification, error };
};
